final:
module RefModule (  
    input clk,  
    input rst,  
    input serial_in,  
    output reg [1:0] q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            q <= 2'b00;  
        else  
            q <= {q[0], serial_in};  
    end  
endmodule
